module binary_to_gray
(
  input [3:0] invalid_binary,
  output [3:0] gray
);

  assign gray[3] = invalid_binary[3];
  assign gray[2] = invalid_binary[3] ^ invalid_binary[2];
  assign gray[1] = invalid_binary[2] ^ invalid_binary[1];
  assign gray[0] = invalid_binary[1] ^ invalid_binary[0];

endmodule
